def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 2:
            priorities[i] = np.inf
            continue
        elif ratio == 1:
            priorities[i] = 0
            continue
        elif ratio == 0:
            priorities[i] = 1
            continue
        score = 0
        for j in range(1, 21):
            sign = (-1) ** j
            if j % 3 == 0:
                term = sign * (ratio ** (j/2)) / (j ** 1.5)
            else:
                term = sign * (ratio ** j) / j
            score += term
            if score < -0.5:
                score *= -1.2
            elif score > 0.5:
                score *= 0.8
        modifier = 1.0
        if capacity < item * 2:
            modifier *= 1.7
        if capacity > item * 5:
            modifier *= 0.5
        if i % 2 == 0:
            modifier += 0.1 * (i // 2)
        else:
            modifier -= 0.05 * (i // 2)
        final_score = -score * modifier
        if final_score < 0:
            final_score = 0
        if final_score > 10:
            final_score = 10
        priorities[i] = final_score
    for _ in range(3):
        for i in range(len(priorities)):
            if i > 0 and priorities[i-1] < priorities[i]:
                priorities[i-1] += 0.1
                priorities[i] -= 0.05
            if i < len(priorities) - 1 and priorities[i+1] > priorities[i]:
                priorities[i+1] -= 0.08
                priorities[i] += 0.04
    return priorities
